// Función para generar el archivo TypeScript
function generateHSK20File() {
  const allBooks = [];
  const wordsPerLesson = 10;

  // HSK 1
  const hsk1Lessons = [];
  const totalLessonsHSK1 = Math.ceil(HSK1_DATA.length / wordsPerLesson);

  for (let i = 0; i < totalLessonsHSK1; i++) {
    const start = i * wordsPerLesson;
    const end = Math.min(start + wordsPerLesson, HSK1_DATA.length);
    const lessonWords = HSK1_DATA.slice(start, end);

    hsk1Lessons.push({
      key: `hsk1_v2_leccion_${i + 1}`,
      label: `HSK 1 v2.0 - Lección ${i + 1}`,
      cards: lessonWords
    });
  }

  allBooks.push({
    id: 'hsk1_v2',
    label: `HSK 1 v2.0 (${totalLessonsHSK1} lecciones - ${HSK1_DATA.length} palabras)`,
    lessons: hsk1Lessons
  });

  // HSK 2
  const hsk2Lessons = [];
  const totalLessonsHSK2 = Math.ceil(HSK2_DATA.length / wordsPerLesson);

  for (let i = 0; i < totalLessonsHSK2; i++) {
    const start = i * wordsPerLesson;
    const end = Math.min(start + wordsPerLesson, HSK2_DATA.length);
    const lessonWords = HSK2_DATA.slice(start, end);

    hsk2Lessons.push({
      key: `hsk2_v2_leccion_${i + 1}`,
      label: `HSK 2 v2.0 - Lección ${i + 1}`,
      cards: lessonWords
    });
  }

  allBooks.push({
    id: 'hsk2_v2',
    label: `HSK 2 v2.0 (${totalLessonsHSK2} lecciones - ${HSK2_DATA.length} palabras)`,
    lessons: hsk2Lessons
  });

  // HSK 3
  const hsk3Lessons = [];
  const totalLessonsHSK3 = Math.ceil(HSK3_DATA.length / wordsPerLesson);

  for (let i = 0; i < totalLessonsHSK3; i++) {
    const start = i * wordsPerLesson;
    const end = Math.min(start + wordsPerLesson, HSK3_DATA.length);
    const lessonWords = HSK3_DATA.slice(start, end);

    hsk3Lessons.push({
      key: `hsk3_v2_leccion_${i + 1}`,
      label: `HSK 3 v2.0 - Lección ${i + 1}`,
      cards: lessonWords
    });
  }

  allBooks.push({
    id: 'hsk3_v2',
    label: `HSK 3 v2.0 (${totalLessonsHSK3} lecciones - ${HSK3_DATA.length} palabras)`,
    lessons: hsk3Lessons
  });

  // HSK 4
  const hsk4Lessons = [];
  const totalLessonsHSK4 = Math.ceil(HSK4_DATA.length / wordsPerLesson);

  for (let i = 0; i < totalLessonsHSK4; i++) {
    const start = i * wordsPerLesson;
    const end = Math.min(start + wordsPerLesson, HSK4_DATA.length);
    const lessonWords = HSK4_DATA.slice(start, end);

    hsk4Lessons.push({
      key: `hsk4_v2_leccion_${i + 1}`,
      label: `HSK 4 v2.0 - Lección ${i + 1}`,
      cards: lessonWords
    });
  }

  allBooks.push({
    id: 'hsk4_v2',
    label: `HSK 4 v2.0 (${totalLessonsHSK4} lecciones - ${HSK4_DATA.length} palabras)`,
    lessons: hsk4Lessons
  });

  // Generar el output TypeScript
  let output = `// Vocabulario HSK 2.0 oficial - Con ejemplos en español
// Generado automáticamente - ${new Date().toISOString().split('T')[0]}

import { Book } from './vocabulary';

export const HSK_2_0_BOOKS: Book[] = [\n`;

  for (const book of allBooks) {
    output += `  {\n`;
    output += `    id: '${book.id}',\n`;
    output += `    label: '${book.label}',\n`;
    output += `    lessons: [\n`;

    for (const lesson of book.lessons) {
      output += `      {\n`;
      output += `        key: '${lesson.key}',\n`;
      output += `        label: '${lesson.label}',\n`;
      output += `        cards: [\n`;

      for (const word of lesson.cards) {
        output += `          { chino: '${word.chino}', pinyin: '${word.pinyin}', significado: '${word.significado}'`;

        if (word.ejemplo) {
          output += `, ejemplo: { chino: '${word.ejemplo.chino}', pinyin: '${word.ejemplo.pinyin}', significado: '${word.ejemplo.significado}' }`;
        }

        output += ` },\n`;
      }

      output += `        ],\n`;
      output += `      },\n`;
    }

    output += `    ],\n`;
    output += `  },\n`;
  }

  output += `];\n`;

  return output;
}

// Generar archivo
const outputPath = path.join(__dirname, 'src', 'app', 'data', 'hsk-2.0-vocabulary.ts');
const content = generateHSK20File();
fs.writeFileSync(outputPath, content, 'utf8');

